import React, { useState } from 'react';
import { Card, CardContent, Box, Grid, Divider, Button, IconButton, Menu, MenuItem, ListItemIcon, ListItemText, Badge, CircularProgress } from '@mui/material';
import FAWTypography from '../../FAWTypography';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import FAWTooltip from '../../FAWTooltip';
import FAWButton from '../../FAWButton';
import { colors } from '../../../../utils/designTokens';
import MoreIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/More.js";
import AttachIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Attach.js";
import ExternalLinkIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ExternalLink.js";
import AssurancePlansIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/AssurancePlans.js";
import SummarizeIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Summarize.js";
import ReloadIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Reload.js";
import SearchIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Search.js";
import ReviewIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Review.js";

/**
 * Helper function to convert hex color to rgba
 */
const hexToRgba = (hex, alpha = 1) => {
    if (!hex) return null;
    const cleanHex = hex.replace('#', '');
    const r = parseInt(cleanHex.substr(0, 2), 16);
    const g = parseInt(cleanHex.substr(2, 2), 16);
    const b = parseInt(cleanHex.substr(4, 2), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const WorkItemDetailsCards = ({
    thirdParty = {},
    workflow = {},
    showThirdPartyProfile = false,
    showAttachments = false,
    showActions = false,
    canGenerateCaseSummary = false,
    canReassignCase = false,
    workItemId = 0,
    responseContainerId = 0,
    workflowId = 0,
    useFloatingWindow = false,
    initialAttachments = [],
    onThirdPartyProfileClick = null,
    onAddAttachmentClick = null,
    onViewSubmittedFormClick = null,
    isComplete = false,
    canReopenCompletedCases = false,
    reopenWorkItemUrl = ''
}) => {
    const [actionsMenuAnchor, setActionsMenuAnchor] = useState(null);
    const [isResetting, setIsResetting] = useState(false);
    const handleButtonClick = (handler) => {
        if (!handler) return;
        if (typeof handler === 'string') {
            const fn = window[handler];
            if (typeof fn === 'function') {
                fn();
            }
        } else if (typeof handler === 'function') {
            handler();
        }
    };

    const handleActionsMenuOpen = (event) => {
        setActionsMenuAnchor(event.currentTarget);
    };

    const handleActionsMenuClose = () => {
        setActionsMenuAnchor(null);
    };

    const handleMenuAction = (actionHandler) => {
        handleActionsMenuClose();
        setTimeout(() => {
            handleButtonClick(actionHandler);
        }, 100);
    };
    const renderRow = (label, value, isLast = false) => (
        <Box key={label} sx={{ position: 'relative' }}>
            <Box
                sx={{
                    display: 'flex',
                    alignItems: 'center',
                    paddingY: 1.5,
                    paddingX: 0,
                }}
            >
                <Box
                    sx={{
                        flexBasis: '50%',
                        flexShrink: 0,
                        minWidth: '120px',
                        maxWidth: '50%',
                    }}
                >
                    <FAWTypography
                        variant="body2"
                        sx={{
                            fontWeight: 600,
                            color: colors.type.default,
                            fontSize: '16px',
                            lineHeight: '24px',
                        }}
                    >
                        {label}
                    </FAWTypography>
                </Box>
                <Box
                    sx={{
                        flexBasis: '50%',
                        flexShrink: 0,
                        flexGrow: 1,
                        maxWidth: '50%',
                        overflow: 'hidden',
                    }}
                >
                    {value ? (
                        typeof value === 'string' ? (
                            <FAWTooltip title={value}>
                                <Box
                                    component="span"
                                    sx={{
                                        display: 'inline-block',
                                        maxWidth: '100%',
                                        overflow: 'hidden',
                                        textOverflow: 'ellipsis',
                                        whiteSpace: 'nowrap',
                                        cursor: 'default',
                                    }}
                                >
                                    <FAWTypography
                                        variant="body2"
                                        noWrap
                                        component="span"
                                        sx={{
                                            fontWeight: 400,
                                            color: colors.type.default,
                                            fontSize: '16px',
                                            lineHeight: '24px',
                                            maxWidth: '100%',
                                            overflow: 'hidden',
                                            textOverflow: 'ellipsis',
                                        }}
                                    >
                                        {value}
                                    </FAWTypography>
                                </Box>
                            </FAWTooltip>
                        ) : (
                            value
                        )
                    ) : (
                        <span style={{ color: colors.type.tertiary }}>—</span>
                    )}
                </Box>
            </Box>
            {!isLast && (
                <Divider
                    sx={{
                        borderColor: colors.ui.border.static,
                        borderWidth: '1px',
                        position: 'absolute',
                        bottom: 0,
                        left: 0,
                        right: 0,
                    }}
                />
            )}
        </Box>
    );

    const renderStatusRow = (label, value, isLast = false) => {
        const showResetButton = isComplete && canReopenCompletedCases;

        return (
            <Box key={label} sx={{ position: 'relative' }}>
                <Box
                    sx={{
                        display: 'flex',
                        alignItems: 'center',
                        paddingY: 1.5,
                        paddingX: 0,
                    }}
                >
                    <Box
                        sx={{
                            flexBasis: '50%',
                            flexShrink: 0,
                            minWidth: '120px',
                            maxWidth: '50%',
                        }}
                    >
                        <FAWTypography
                            variant="body2"
                            sx={{
                                fontWeight: 600,
                                color: colors.type.default,
                                fontSize: '16px',
                                lineHeight: '24px',
                            }}
                        >
                            {label}
                        </FAWTypography>
                    </Box>
                    <Box
                        sx={{
                            flexBasis: '50%',
                            flexShrink: 0,
                            flexGrow: 1,
                            maxWidth: '50%',
                            overflow: 'hidden',
                            display: 'flex',
                            alignItems: 'center',
                            gap: 1.5,
                        }}
                    >
                        {value ? (
                            <FAWTooltip title={value}>
                                <Box
                                    component="span"
                                    sx={{
                                        display: 'inline-block',
                                        maxWidth: showResetButton ? 'calc(100% - 140px)' : '100%',
                                        overflow: 'hidden',
                                        textOverflow: 'ellipsis',
                                        whiteSpace: 'nowrap',
                                        cursor: 'default',
                                    }}
                                >
                                    <FAWTypography
                                        variant="body2"
                                        noWrap
                                        component="span"
                                        sx={{
                                            fontWeight: 400,
                                            color: colors.type.default,
                                            fontSize: '16px',
                                            lineHeight: '24px',
                                            maxWidth: '100%',
                                            overflow: 'hidden',
                                            textOverflow: 'ellipsis',
                                        }}
                                    >
                                        {value}
                                    </FAWTypography>
                                </Box>
                            </FAWTooltip>
                        ) : (
                            <span style={{ color: colors.type.tertiary }}>—</span>
                        )}
                        {showResetButton && (
                            <FAWButton
                                variant="contained"
                                color="primary"
                                size="small"
                                disabled={isResetting}
                                onClick={() => {

                                    if (reopenWorkItemUrl) {
                                        var spinner = document.getElementById('loading-spinner');
                                        if (spinner) {
                                            spinner.style.visibility = 'visible';
                                            spinner.style.opacity = '1';
                                            spinner.style.display = 'flex';
                                        }
                                        setIsResetting(true);
                                        setTimeout(() => {
                                            window.location.href = reopenWorkItemUrl;
                                        }, 150);
                                    } else {
                                        console.warn('[WorkItemDetailsCards] reopenWorkItemUrl is empty, cannot reset workflow');
                                    }
                                }}
                                startIcon={isResetting ? <CircularProgress size={16} sx={{ color: 'inherit' }} /> : null}
                            >
                                {isResetting ? 'Resetting...' : 'Reset Workflow'}
                            </FAWButton>
                        )}
                    </Box>
                </Box>
                {!isLast && (
                    <Divider
                        sx={{
                            borderColor: colors.ui.border.static,
                            borderWidth: '1px',
                            position: 'absolute',
                            bottom: 0,
                            left: 0,
                            right: 0,
                        }}
                    />
                )}
            </Box>
        );
    };

    const getRiskRatingColor = (rating) => {
        const ratingLower = (rating || '').toLowerCase();
        if (ratingLower.includes('highest') || ratingLower.includes('high')) {
            return { backgroundColor: colors.status.error, color: colors.type.inverse };
        }
        if (ratingLower.includes('medium')) {
            return { backgroundColor: colors.status.warning, color: colors.type.inverse };
        }
        if (ratingLower.includes('low')) {
            return { backgroundColor: colors.status.success, color: colors.type.inverse };
        }
        return { backgroundColor: colors.type.tertiary, color: colors.type.inverse };
    };

    const getStatusColor = (status) => {
        const statusLower = (status || '').toLowerCase();
        if (statusLower === 'active') {
            return { backgroundColor: colors.status.success, color: colors.type.default };
        }
        if (statusLower === 'inactive' || statusLower === 'closed') {
            return { backgroundColor: colors.type.tertiary, color: colors.type.inverse };
        }
        return { backgroundColor: colors.action.link.default, color: colors.type.inverse };
    };

    const thirdPartyRows = [
        {
            label: 'Workflow Initiator',
            value: thirdParty.workflowInitiator || '',
        },
        {
            label: 'Third Party',
            value: thirdParty.thirdPartyName || '',
        },
        {
            label: 'Third Party Type',
            value: thirdParty.thirdPartyType || '',
        },
        {
            label: 'Third Party Category',
            value: thirdParty.thirdPartyCategory || '',
        },
        {
            label: 'Risk Rating',
            value: thirdParty.riskRating || '',
        },
        {
            label: 'Status',
            value: thirdParty.status || '',
            isStatus: true,
        },
    ];

    const workflowRows = [
        {
            label: 'Category',
            value: workflow.category || '',
        },
        {
            label: 'Sub-Category',
            value: workflow.subCategory || '',
        },
        {
            label: 'Form',
            value: workflow.form || '',
        },
        {
            label: 'Workflow ID',
            value: workflow.workflowId || '',
        },
        {
            label: 'Workflow Created',
            value: workflow.workflowCreated || '',
        },
        {
            label: 'Expected Completion',
            value: workflow.expectedCompletion || '',
        },
    ];

    return (
        <FAWErrorBoundary
            title="Work Item Details Cards Error"
            message="An error occurred while rendering the work item details cards."
            showDetails={false}
        >
            <Box
                sx={{
                    backgroundColor: colors.background.selected,
                    borderRadius: 1.5,
                    padding: 3,
                    width: '100%',
                    display: 'flex',
                    flexDirection: 'column',
                    gap: 3,
                }}
            >
                {/* Header Row with Title and Buttons */}
                <Box
                    sx={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        gap: 1.5,
                        width: '100%',
                    }}
                >
                    <FAWTypography
                        variant="h6"
                        sx={{
                            fontWeight: 700,
                            fontSize: '22px',
                            lineHeight: '28px',
                            color: colors.type.default,
                        }}
                    >
                        Workflow attributes
                    </FAWTypography>

                    <Box
                        sx={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: 1.5,
                        }}
                    >
                        {showThirdPartyProfile && (
                            <Button
                                variant="text"
                                size="small"
                                startIcon={<ExternalLinkIcon />}
                                onClick={() => handleButtonClick(onThirdPartyProfileClick)}
                                sx={{
                                    textTransform: 'none',
                                    fontWeight: 600,
                                    fontSize: '16px',
                                    lineHeight: '25.5px',
                                    minHeight: '40px',
                                    paddingX: 2,
                                    paddingY: 1,
                                    color: colors.type.default,
                                    '&:hover': {
                                        backgroundColor: colors.type.default ? hexToRgba(colors.type.default, 0.04) : 'rgba(40, 46, 55, 0.04)',
                                    },
                                }}
                            >
                                See 3P Profile
                            </Button>
                        )}
                        {Number(responseContainerId) > 0 && (
                            <FAWTooltip title="View Submitted Form">
                                <Button
                                    variant="text"
                                    size="small"
                                    startIcon={<ReviewIcon />}
                                    onClick={() => handleButtonClick(onViewSubmittedFormClick || 'handleViewSubmittedFormClick')}
                                    sx={{
                                        textTransform: 'none',
                                        fontWeight: 600,
                                        fontSize: '16px',
                                        lineHeight: '25.5px',
                                        minHeight: '40px',
                                        paddingX: 2,
                                        paddingY: 1,
                                        color: colors.type.default,
                                        '&:hover': {
                                            backgroundColor: colors.type.default ? hexToRgba(colors.type.default, 0.04) : 'rgba(40, 46, 55, 0.04)',
                                        },
                                    }}
                                >
                                    View Submitted Form
                                </Button>
                            </FAWTooltip>
                        )}
                        {showAttachments && (
                            <Button
                                variant="text"
                                size="small"
                                startIcon={
                                    initialAttachments && initialAttachments.length > 0 ? (
                                        <Badge
                                            badgeContent={initialAttachments.length}
                                            color="primary"
                                            sx={{
                                                '& .MuiBadge-badge': {
                                                    fontSize: '11px',
                                                    height: '18px',
                                                    minWidth: '18px',
                                                    borderRadius: '9px',
                                                },
                                            }}
                                        >
                                            <AttachIcon />
                                        </Badge>
                                    ) : (
                                        <AttachIcon />
                                    )
                                }
                                onClick={() => handleButtonClick(onAddAttachmentClick || 'handleAddAttachmentClick')}
                                sx={{
                                    textTransform: 'none',
                                    fontWeight: 600,
                                    fontSize: '16px',
                                    lineHeight: '25.5px',
                                    minHeight: '40px',
                                    paddingX: 2,
                                    paddingY: 1,
                                    color: colors.type.default,
                                    '&:hover': {
                                        backgroundColor: colors.type.default ? hexToRgba(colors.type.default, 0.04) : 'rgba(40, 46, 55, 0.04)',
                                    },
                                }}
                            >
                                Add attachment
                            </Button>
                        )}
                        {showActions && (
                            <>
                                <IconButton
                                    onClick={handleActionsMenuOpen}
                                    sx={{
                                        color: colors.type.default,
                                        '&:hover': {
                                            backgroundColor: hexToRgba(colors.type.default, 0.04),
                                        },
                                    }}
                                >
                                    <MoreIcon />
                                </IconButton>
                                <Menu
                                    anchorEl={actionsMenuAnchor}
                                    open={Boolean(actionsMenuAnchor)}
                                    onClose={handleActionsMenuClose}
                                    anchorOrigin={{
                                        vertical: 'bottom',
                                        horizontal: 'right',
                                    }}
                                    transformOrigin={{
                                        vertical: 'top',
                                        horizontal: 'right',
                                    }}
                                    PaperProps={{
                                        sx: {
                                            mt: 1,
                                            minWidth: 220,
                                            boxShadow: '0px 4px 20px rgba(0, 0, 0, 0.15)',
                                            borderRadius: '8px',
                                            border: `1px solid ${colors.ui.border.static}`,
                                        },
                                    }}
                                >
                                    <MenuItem
                                        onClick={() => handleMenuAction('handleWorkflowInitiationLog')}
                                        sx={{
                                            py: 1.5,
                                            px: 2,
                                            '&:hover': {
                                                backgroundColor: colors.background.secondary,
                                            },
                                        }}
                                    >
                                        <ListItemIcon sx={{ minWidth: 40 }}>
                                            <AssurancePlansIcon size="md" />
                                        </ListItemIcon>
                                        <ListItemText
                                            primary="Workflow Initiation Log"
                                            primaryTypographyProps={{
                                                fontSize: '14px',
                                                fontWeight: 500,
                                            }}
                                        />
                                    </MenuItem>
                                    {canGenerateCaseSummary && (
                                        <MenuItem
                                            onClick={() => handleMenuAction('handleCreateWorkflowSummary')}
                                            sx={{
                                                py: 1.5,
                                                px: 2,
                                                '&:hover': {
                                                    backgroundColor: colors.background.secondary,
                                                },
                                            }}
                                        >
                                            <ListItemIcon sx={{ minWidth: 40 }}>
                                                <SummarizeIcon size="md" />
                                            </ListItemIcon>
                                            <ListItemText
                                                primary="Create Workflow Summary"
                                                primaryTypographyProps={{
                                                    fontSize: '14px',
                                                    fontWeight: 500,
                                                }}
                                            />
                                        </MenuItem>
                                    )}
                                    {canReassignCase && (
                                        <MenuItem
                                            onClick={() => handleMenuAction('handleRecategorize')}
                                            sx={{
                                                py: 1.5,
                                                px: 2,
                                                '&:hover': {
                                                    backgroundColor: colors.background.secondary,
                                                },
                                            }}
                                        >
                                            <ListItemIcon sx={{ minWidth: 40 }}>
                                                <ReloadIcon size="md" />
                                            </ListItemIcon>
                                            <ListItemText
                                                primary="Recategorize"
                                                primaryTypographyProps={{
                                                    fontSize: '14px',
                                                    fontWeight: 500,
                                                }}
                                            />
                                        </MenuItem>
                                    )}
                                    <MenuItem
                                        onClick={() => {
                                            handleActionsMenuClose();
                                            if (window.setWorkItemView) {
                                                window.setWorkItemView('findAdditionalFields', {
                                                    workItemId: workItemId,
                                                    searchUrl: '/WorkItem/SearchUDFsApi'
                                                });
                                            }
                                        }}
                                        sx={{
                                            py: 1.5,
                                            px: 2,
                                            '&:hover': {
                                                backgroundColor: colors.background.secondary,
                                            },
                                        }}
                                    >
                                        <ListItemIcon sx={{ minWidth: 40 }}>
                                            <SearchIcon size="md" />
                                        </ListItemIcon>
                                        <ListItemText
                                            primary="Find Additional Fields"
                                            primaryTypographyProps={{
                                                fontSize: '14px',
                                                fontWeight: 500,
                                            }}
                                        />
                                    </MenuItem>
                                </Menu>
                            </>
                        )}
                    </Box>
                </Box>

                <Grid container spacing={3} sx={{ width: '100%' }}>
                    <Grid item xs={12} md={6}>
                        <Card
                            sx={{
                                borderRadius: 1,
                                boxShadow: 'none',
                                backgroundColor: colors.background.default,
                                height: '100%',
                                p: 1
                            }}
                        >
                            <CardContent sx={{ padding: 1 }}>
                                <Box>
                                    {thirdPartyRows.map((row, index) =>
                                        row.isStatus ? (
                                            renderStatusRow(
                                                row.label,
                                                row.value,
                                                index === thirdPartyRows.length - 1
                                            )
                                        ) : (
                                            renderRow(
                                                row.label,
                                                row.value,
                                                index === thirdPartyRows.length - 1
                                            )
                                        )
                                    )}
                                </Box>
                            </CardContent>
                        </Card>
                    </Grid>

                    <Grid item xs={12} md={6}>
                        <Card
                            sx={{
                                borderRadius: '12px',
                                boxShadow: 'none',
                                backgroundColor: colors.background.default,
                                height: '100%',
                            }}
                        >
                            <CardContent sx={{ padding: 2 }}>
                                <Box>
                                    {workflowRows.map((row, index) =>
                                        renderRow(
                                            row.label,
                                            row.value,
                                            index === workflowRows.length - 1
                                        )
                                    )}
                                </Box>
                            </CardContent>
                        </Card>
                    </Grid>
                </Grid>
            </Box>
        </FAWErrorBoundary>
    );
};

export default WorkItemDetailsCards;